import React from 'react';
import { Link } from 'react-router-dom';
import { Button } from 'react-bootstrap';

function Home() {
  return (
    <div className="container mt-5">
      <h1>Welcome to the Employee Management App</h1>
      <div className="mt-3">
        <Link to="/employees" className="btn btn-primary mr-2">Manage Employees</Link>
        <Link to="/company-items" className="btn btn-primary">Manage Company Items</Link>
      </div>
    </div>
  );
}

export default Home;
